function saudacao(nome: string): void {
  console.log(`Olá, ${nome}! Bem-vindo!`);
}

saudacao("Aria");
saudacao("Kael");
saudacao("Luna");

function atacar(nomeInimigo: string, dano: number): void {
  console.log(`Você atacou ${nomeInimigo} causando ${dano} de dano!`);
}

atacar("Goblin", 25);
atacar("Dragão", 50);
atacar("Slime", 10);

function calcularDano(forca: number, arma: number): number {
  return forca * arma;
}

const dano: number = calcularDano(18, 3);
console.log(`Dano total: ${dano}`);

// Pode usar direto numa expressão:
console.log(`Dano crítico: ${calcularDano(18, 3) * 2}`);

function maiorDeDois(a: number, b: number): number {
  if (a > b) {
    return a;
  } else {
    return b;
  }
}

console.log(maiorDeDois(42, 17));
console.log(maiorDeDois(5, 99));
console.log(maiorDeDois(10, 10));

function ehMaiorDeIdade(idade: number): boolean {
  return idade >= 18;
}

console.log(ehMaiorDeIdade(12));
console.log(ehMaiorDeIdade(21));

function descrever(nome: string, nivel: number): string {
  return `${nome} está no nível ${nivel}`;
}

console.log(descrever("Aria", 5));

// Função tradicional:
function dobrar(n: number): number {
  return n * 2;
}

// Mesma coisa como arrow function:
const dobrarArrow = (n: number): number => {
  return n * 2;
};

// Versão ultra-curta (só uma expressão):
const dobrarCurta = (n: number): number => n * 2;

console.log(dobrar(5));
console.log(dobrarArrow(5));
console.log(dobrarCurta(5));

