function validarSenha(senha: string): string {
  if (senha.length < 6) {
    return "Fraca";
  } else if (senha.length < 10) {
    return "Média";
  } else {
    return "Forte";
  }
}

console.log(validarSenha("abc"));
console.log(validarSenha("abc12345"));
console.log(validarSenha("senhaForte123"));

